#include <stdio.h>
#include <stdlib.h>

/*
 * Four-Variable Karnaugh Map Minimization
 * Implements K-Map solving for F(A,B,C,D) = Σm(...)
 */

#define ROWS 4
#define COLS 4

// Gray code mapping for row/column indices
// Index: 0 1 2 3
// Gray: 00 01 11 10
const char* grayRow[4] = {"00", "01", "11", "10"}; // AB
const char* grayCol[4] = {"00", "01", "11", "10"}; // CD

typedef struct {
 int row, col;
} Cell;

typedef struct {
 Cell cells[16];
 int size;
} Group;

// Global K-Map
int kmap[ROWS][COLS];

// Initialize K-Map with zeros
void initKMap() {
 for (int i = 0; i < ROWS; i++) {
 for (int j = 0; j < COLS; j++) {
 kmap[i][j] = 0;
 }
 }
}

// Set minterms (cells with 1)
void setMinterms(int minterms[], int count) {
 for (int i = 0; i < count; i++) {
 int m = minterms[i];
 int row = m / 4;
 int col = m % 4;
 kmap[row][col] = 1;
 }
}

// Display K-Map
void displayKMap() {
 printf("\n K-Map for F(A,B,C,D)\n");
 printf(" CD ->\n");
 printf("AB\\CD ");

 // Column headers (Gray code)
 for (int j = 0; j < COLS; j++) {
 printf("%s ", grayCol[j]);
 }
 printf("\n");
 printf("------\n");

 for (int i = 0; i < ROWS; i++) {
 printf("%s ", grayRow[i]);
 for (int j = 0; j < COLS; j++) {
 printf("%d ", kmap[i][j]);
 }
 printf("\n");
 }
 printf("\n");
}

// Get minterm number from row, col
int getMinterm(int row, int col) {
 return row * 4 + col;
}

// Check if all cells in a group are 1
int allOnes(Cell cells[], int size) {
 for (int i = 0; i < size; i++) {
 if (kmap[cells[i].row][cells[i].col] != 1) {
 return 0;
 }
 }
 return 1;
}

// Find 4-cell groups (2x2 rectangles)
void findGroups4(Group groups[], int *groupCount) {
 *groupCount = 0;

 // Regular 2x2 groups
 for (int r = 0; r < 3; r++) {
 for (int c = 0; c < 3; c++) {
 Cell cells[4] = {
 {r, c}, {r, c+1}, {r+1, c}, {r+1, c+1}
 };
 if (allOnes(cells, 4)) {
 for (int i = 0; i < 4; i++) {
 groups[*groupCount].cells[i] = cells[i];
 }
 groups[*groupCount].size = 4;
 (*groupCount)++;
 }
 }
 }

 // Wrap-around: top-bottom (column pairs)
 for (int c = 0; c < 3; c++) {
 Cell cells[4] = {{3,c}, {3,c+1}, {0,c}, {0,c+1}};
 if (allOnes(cells, 4)) {
 for (int i = 0; i < 4; i++) {
 groups[*groupCount].cells[i] = cells[i];
 }
 groups[*groupCount].size = 4;
 (*groupCount)++;
 }
 }

 // Wrap-around: left-right (row pairs)
 for (int r = 0; r < 3; r++) {
 Cell cells[4] = {{r,3}, {r+1,3}, {r,0}, {r+1,0}};
 if (allOnes(cells, 4)) {
 for (int i = 0; i < 4; i++) {
 groups[*groupCount].cells[i] = cells[i];
 }
 groups[*groupCount].size = 4;
 (*groupCount)++;
 }
 }

 // Four corners
 Cell corners[4] = {{0,0}, {0,3}, {3,0}, {3,3}};
 if (allOnes(corners, 4)) {
 for (int i = 0; i < 4; i++) {
 groups[*groupCount].cells[i] = corners[i];
 }
 groups[*groupCount].size = 4;
 (*groupCount)++;
 }
}

// Find 2-cell groups (pairs)
void findGroups2(Group groups[], int *groupCount, int existingCells[][COLS]) {
 *groupCount = 0;

 // Horizontal pairs
 for (int r = 0; r < ROWS; r++) {
 for (int c = 0; c < 3; c++) {
 Cell cells[2] = {{r, c}, {r, c+1}};
 if (allOnes(cells, 2) && !existingCells[r][c] && !existingCells[r][c+1]) {
 groups[*groupCount].cells[0] = cells[0];
 groups[*groupCount].cells[1] = cells[1];
 groups[*groupCount].size = 2;
 (*groupCount)++;
 }
 }
 // Wrap-around horizontal
 Cell cells[2] = {{r, 3}, {r, 0}};
 if (allOnes(cells, 2) && !existingCells[r][3] && !existingCells[r][0]) {
 groups[*groupCount].cells[0] = cells[0];
 groups[*groupCount].cells[1] = cells[1];
 groups[*groupCount].size = 2;
 (*groupCount)++;
 }
 }

 // Vertical pairs
 for (int c = 0; c < COLS; c++) {
 for (int r = 0; r < 3; r++) {
 Cell cells[2] = {{r, c}, {r+1, c}};
 if (allOnes(cells, 2) && !existingCells[r][c] && !existingCells[r+1][c]) {
 groups[*groupCount].cells[0] = cells[0];
 groups[*groupCount].cells[1] = cells[1];
 groups[*groupCount].size = 2;
 (*groupCount)++;
 }
 }
 // Wrap-around vertical
 Cell cells[2] = {{3, c}, {0, c}};
 if (allOnes(cells, 2) && !existingCells[3][c] && !existingCells[0][c]) {
 groups[*groupCount].cells[0] = cells[0];
 groups[*groupCount].cells[1] = cells[1];
 groups[*groupCount].size = 2;
 (*groupCount)++;
 }
 }
}

// Get product term for a group
void getProductTerm(Group group, char *term) {
 int rows[16], cols[16];
 int count = group.size;

 for (int i = 0; i < count; i++) {
 rows[i] = group.cells[i].row;
 cols[i] = group.cells[i].col;
 }

 term[0] = '\0';
 char temp[100] = "";

 // Check A (row MSB - first bit of AB)
 int a_values[4];
 for (int i = 0; i < count; i++) {
 a_values[i] = grayRow[rows[i]][0] - '0';
 }
 if (a_values[0] == a_values[1] && (count > 2 ? a_values[1] == a_values[2] : 1)) {
 sprintf(temp + strlen(temp), "%s", a_values[0] ? "A" : "A'");
 }

 // Check B (row LSB - second bit of AB)
 int b_values[4];
 for (int i = 0; i < count; i++) {
 b_values[i] = grayRow[rows[i]][1] - '0';
 }
 if (b_values[0] == b_values[1] && (count > 2 ? b_values[1] == b_values[2] : 1)) {
 sprintf(temp + strlen(temp), "%s", b_values[0] ? "B" : "B'");
 }

 // Check C (col MSB - first bit of CD)
 int c_values[4];
 for (int i = 0; i < count; i++) {
 c_values[i] = grayCol[cols[i]][0] - '0';
 }
 if (c_values[0] == c_values[1] && (count > 2 ? c_values[1] == c_values[2] : 1)) {
 sprintf(temp + strlen(temp), "%s", c_values[0] ? "C" : "C'");
 }

 // Check D (col LSB - second bit of CD)
 int d_values[4];
 for (int i = 0; i < count; i++) {
 d_values[i] = grayCol[cols[i]][1] - '0';
 }
 if (d_values[0] == d_values[1] && (count > 2 ? d_values[1] == d_values[2] : 1)) {
 sprintf(temp + strlen(temp), "%s", d_values[0] ? "D" : "D'");
 }

 strcpy(term, strlen(temp) > 0 ? temp : "1");
}

int main() {
 printf("========================================\n");
 printf("Four-Variable Karnaugh Map Minimization\n");
 printf("Example: F(A,B,C,D) = Σm(0,2,5,7,8,10,13,15)\n");
 printf("========================================\n");

 // Initialize
 initKMap();

 // Set minterms for example: Σm(0,2,5,7,8,10,13,15)
 int minterms[] = {0, 2, 5, 7, 8, 10, 13, 15};
 int numMinterms = sizeof(minterms) / sizeof(minterms[0]);

 setMinterms(minterms, numMinterms);
 displayKMap();

 // Track used cells
 int used[ROWS][COLS] = {0};

 // Find 4-cell groups first (larger groups = more simplification)
 Group groups4[20];
 int count4;
 findGroups4(groups4, &count4);

 printf("Found Groups (Prime Implicants):\n");
 printf("----------------------------------------\n");

 // Mark used cells
 for (int i = 0; i < count4; i++) {
 for (int j = 0; j < 4; j++) {
 used[groups4[i].cells[j].row][groups4[i].cells[j].col] = 1;
 }
 }

 // Find 2-cell groups for remaining 1s
 Group groups2[20];
 int count2;
 findGroups2(groups2, &count2, used);

 // Print results
 int totalGroups = count4 + count2;
 char terms[20][50];

 for (int i = 0; i < count4; i++) {
 getProductTerm(groups4[i], terms[i]);
 printf("Group %d: 4 cells -> %s\n", i+1, terms[i]);
 printf(" Minterms: ");
 for (int j = 0; j < 4; j++) {
 printf("m%d ", getMinterm(groups4[i].cells[j].row, groups4[i].cells[j].col));
 }
 printf("\n");
 }

 for (int i = 0; i < count2; i++) {
 getProductTerm(groups2[i], terms[count4 + i]);
 printf("Group %d: 2 cells -> %s\n", count4 + i + 1, terms[count4 + i]);
 printf(" Minterms: ");
 for (int j = 0; j < 2; j++) {
 printf("m%d ", getMinterm(groups2[i].cells[j].row, groups2[i].cells[j].col));
 }
 printf("\n");
 }

 // Build final expression
 printf("----------------------------------------\n");
 printf("Simplified Expression: F = ");
 for (int i = 0; i < totalGroups; i++) {
 if (i > 0) printf(" + ");
 printf("%s", terms[i]);
 }
 printf("\n\n");

 printf("Verification: This represents XNOR: F = B.D + B'.D'\n");

 return 0;
}
